 1	import type { FC } from 'react';
 2	import { useForkliftTranslation } from 'src/utils/i18n';
 3	
 4	import { ClipboardCopy, Switch, TextInput, Tooltip } from '@patternfly/react-core';
 5	
 6	import type { Field } from './components/list/Fields';
 7	
 8	type ShowFieldWithClipboardCopyProps = {
 9	  value: string;
10	  field?: Field;
11	};
12	
13	/**
14	 * Displays a field with its value. If the value is empty, shows a disabled text input with a tooltip indicating the field is missing.
15	 * If the value is non-empty, displays the value in a read-only format with a clipboard copy functionality.
16	 *
17	 * @property {string} value - The value of the field to display.
18	 * @property {object} field - Object containing details about the field such as label and display type.
19	 */
20	export const FieldWithClipboardCopy: FC<ShowFieldWithClipboardCopyProps> = ({ field, value }) => {
21	  const { t } = useForkliftTranslation();
22	
23	  // Render tooltip for missing value
24	  if (!value) {
25	    return (
26	      <Tooltip
27	        content={
28	          <div>
29	            {t('{{label}} field is missing from the secret data.', { label: field?.label ?? '' })}
30	          </div>
31	        }
32	      >
33	        <TextInput spellCheck="false" value="No value" type="text" isDisabled />
34	      </Tooltip>
35	    );
36	  }
37	
38	  // Determine how to display the field based on its type
39	  const renderFieldByType = () => {
40	    switch (field?.displayType) {
41	      case 'textArea':
42	        return (
43	          <ClipboardCopy
44	            isReadOnly
45	            hoverTip={t('Copy')}
46	            clickTip={t('Copied')}
47	            isCode
48	            variant="expansion"
49	          >
50	            {value}
51	          </ClipboardCopy>
52	        );
53	      case 'switch':
54	        return (
55	          <Switch
56	            aria-label={`Switch for ${field.label}`}
57	            label={`${field.label} is set`}
58	            labelOff={`${field.label} is not set`}
59	            isChecked={value.toLocaleLowerCase() === 'true'}
60	            hasCheckIcon
61	            isDisabled
62	          />
63	        );
64	      case 'text':
65	      case undefined:
66	      default:
67	        return (
68	          <ClipboardCopy isReadOnly hoverTip={t('Copy')} clickTip={t('Copied')} isCode>
69	            {value}
70	          </ClipboardCopy>
71	        );
72	    }
73	  };
74	
75	  return renderFieldByType();
76	};

